window.APUNTES_DATA = {"bloques": [{"id": "fundamentos", "titulo": "Fundamentos", "desc": "Las bases del lenguaje", "rango": [1, 12]}, {"id": "es6", "titulo": "ES6", "desc": "JavaScript moderno (2015+)", "rango": [13, 29]}, {"id": "regex", "titulo": "Expresiones Regulares", "desc": "Patrones de texto", "rango": [30, 40]}, {"id": "debug", "titulo": "Debugging", "desc": "Encontrar y corregir errores", "rango": [41, 45]}, {"id": "data", "titulo": "Estructuras de Datos", "desc": "Manipular arrays y objetos", "rango": [46, 51]}, {"id": "algoritmos", "titulo": "Algoritmos Básicos", "desc": "Resolver problemas paso a paso", "rango": [52, 60]}, {"id": "oop", "titulo": "Programación Orientada a Objetos", "desc": "Constructores, herencia y módulos", "rango": [61, 73]}], "secciones": [{"numero": 1, "titulo": "Variables y Tipos de Datos", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Declaración de variables"}, {"tipo": "codigo", "codigo": "var   x = 5;       // antiguo, evitar\nlet   y = 10;      // puede cambiar\nconst z = 15;      // no puede cambiar (constante)"}, {"tipo": "subtitulo", "texto": "Operadores de asignación compuesta"}, {"tipo": "tabla", "filas": [["**Forma larga**", "**Forma corta (equivalente)**"], ["a = a + 1;", "a++;"], ["a = a + 67;", "a += 67;"], ["a = a - 5;", "a -= 5;"], ["a = a * 3;", "a *= 3;"], ["a = a / 2;", "a /= 2;"]]}]}, {"numero": 2, "titulo": "Cadenas de Texto (Strings)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Comillas dentro de strings"}, {"tipo": "texto", "texto": "Para incluir comillas dobles dentro de un string, usa la barra invertida \\:"}, {"tipo": "codigo", "codigo": "let mom = \"Mi mamá dijo: \\\"tonto\\\"\";"}, {"tipo": "subtitulo", "texto": "Concatenación"}, {"tipo": "codigo", "codigo": "const adj = \"awesome!\";\nlet str = \"freeCodeCamp is \" + adj;\nstr += \" yeah!\";   // concatenar y asignar"}, {"tipo": "subtitulo", "texto": "Largo de una cadena — .length"}, {"tipo": "codigo", "codigo": "let name = \"Jose\";\nconsole.log(name.length);   // 4"}, {"tipo": "subtitulo", "texto": "Acceso por índice (inicia en 0)"}, {"tipo": "codigo", "codigo": "let name = \"Jose\";\nname[0];               // \"J\" (primer carácter)\nname[name.length - 1]; // \"e\" (último carácter)"}, {"tipo": "subtitulo", "texto": "Secuencias de escape"}, {"tipo": "tabla", "filas": [["**Secuencia**", "**Qué hace**"], ["\\n", "Nueva línea"], ["\\t", "Tabulación (sangría)"], ["\\\\", "Barra invertida literal \\"], ["\\\"", "Comillas dobles dentro de string"], ["\\'", "Comilla simple dentro de string"], ["\\r", "Retorno de carro (regresa al inicio)"], ["\\b", "Retroceso (borra carácter anterior)"]]}]}, {"numero": 3, "titulo": "Arrays (Arreglos)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Declaración"}, {"tipo": "codigo", "codigo": "const nums   = [1, 2, 3];\nconst food   = [\"peanut butter\", \"jelly\"];\nconst multi  = [[1, 2], [3, 4]];  // multidimensional"}, {"tipo": "subtitulo", "texto": "Acceso y modificación"}, {"tipo": "codigo", "codigo": "nums[0];         // 1  (primer elemento)\nnums[2];         // 3  (tercer elemento)\nmulti[0][1];     // 2  (fila 0, columna 1)\nnums[0] = 99;    // los arrays SÍ son mutables"}, {"tipo": "subtitulo", "texto": "Métodos principales"}, {"tipo": "tabla", "filas": [["**Método**", "**Qué hace**"], ["arr.push(x)", "Agrega x al FINAL del array"], ["arr.pop()", "Elimina y devuelve el ÚLTIMO elemento"], ["arr.shift()", "Elimina y devuelve el PRIMER elemento"], ["arr.unshift(x)", "Agrega x al INICIO del array"]]}]}, {"numero": 4, "titulo": "Funciones", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Sintaxis básica"}, {"tipo": "codigo", "codigo": "function nombreFuncion(param1, param2) {\n  // código\n  return resultado;\n}\n\nnombreFuncion(arg1, arg2);  // llamar la función"}, {"tipo": "subtitulo", "texto": "Conceptos clave"}, {"tipo": "texto", "texto": "- Parámetros = variables al definir la función (los 'espacios reservados')"}, {"tipo": "texto", "texto": "- Argumentos = valores reales que pasas al llamarla"}, {"tipo": "texto", "texto": "- Sin return → la función devuelve undefined"}, {"tipo": "texto", "texto": "- Con return → devuelve el valor indicado y termina la función"}, {"tipo": "subtitulo", "texto": "Alcance (Scope)"}, {"tipo": "tabla", "filas": [["**Global**", "**Local**"], ["Variable declarada fuera de función. Visible en todo el código.", "Variable declarada dentro de función. Solo existe dentro de ella."], ["let x = 5; // global", "function f() {   let x = 99; // local }"]]}, {"tipo": "codigo", "codigo": "⚠️ Regla de conflicto de alcance\nSi hay una variable local y global con el mismo nombre, la LOCAL gana dentro de la función."}, {"tipo": "subtitulo", "texto": "Return anticipado (Early Return)"}, {"tipo": "texto", "texto": "Cuando se ejecuta return, la función termina inmediatamente. El código después no se ejecuta."}, {"tipo": "codigo", "codigo": "function myFun() {\n  console.log(\"Hello\");\n  return \"World\";\n  console.log(\"byebye\"); // NUNCA se ejecuta\n}"}]}, {"numero": 5, "titulo": "Booleanos y Operadores de Comparación", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Booleanos"}, {"tipo": "texto", "texto": "Solo dos valores posibles: true o false — NUNCA entre comillas (si tienen comillas son texto, no booleanos)."}, {"tipo": "subtitulo", "texto": "Tabla de operadores de comparación"}, {"tipo": "tabla", "filas": [["**Operador**", "**Significado y ejemplo**"], ["==", "Igual **(convierte tipos)**  →  3 == '3' → true"], ["===", "Igual estricto **(sin convertir)**  →  3 === '3' → false"], ["!=", "Diferente **(convierte tipos)**  →  1 != '1' → false"], ["!==", "Diferente estricto  →  3 !== '3' → true"], [">", "Mayor que  →  5 > 3 → true"], [">=", "Mayor o igual que  →  6 >= 6 → true"], ["<", "Menor que  →  5 < 5 → false"], ["<=", "Menor o igual que  →  5 <= 5 → true"]]}, {"tipo": "subtitulo", "texto": "Operadores lógicos"}, {"tipo": "tabla", "filas": [["**Operador**", "**Regla**"], ["&&  (AND)", "true SOLO si AMBAS condiciones son true"], ["││  (OR)", "true si AL MENOS UNA condición es true"], ["!   (NOT)", "Invierte el valor: !true → false"]]}, {"tipo": "codigo", "codigo": "💡 Tip — typeof\nPara conocer el tipo de un valor: typeof 3 → \"number\" | typeof '3' → \"string\""}]}, {"numero": 6, "titulo": "Condicionales (if / else if / else)", "bloque": "fundamentos", "contenido": [{"tipo": "codigo", "codigo": "if (condicion) {\n  // se ejecuta si condicion es true\n} else if (otraCondicion) {\n  // se ejecuta si otraCondicion es true\n} else {\n  // se ejecuta si ninguna fue true\n}"}, {"tipo": "codigo", "codigo": "⚠️ El orden importa\nEl código se evalúa de arriba abajo. El primer if que sea true detiene la cadena."}, {"tipo": "subtitulo", "texto": "Operador ternario (condicional de una línea)"}, {"tipo": "texto", "texto": "Sintaxis:  condicion ? valor_si_true : valor_si_false"}, {"tipo": "codigo", "codigo": "// Equivalente a un if/else completo:\nfunction findGreater(a, b) {\n  return a > b ? \"a is greater\" : \"b is greater or equal\";\n}"}, {"tipo": "subtitulo", "texto": "Ternarios encadenados (múltiples condiciones)"}, {"tipo": "codigo", "codigo": "function findGreaterOrEqual(a, b) {\n  return (a === b) ? \"a and b are equal\"\n       : (a > b)   ? \"a is greater\"\n                   : \"b is greater\";\n}"}]}, {"numero": 7, "titulo": "Switch", "bloque": "fundamentos", "contenido": [{"tipo": "texto", "texto": "Útil cuando tienes muchas comparaciones sobre el mismo valor. Más limpio que varios if/else if encadenados."}, {"tipo": "codigo", "codigo": "switch (val) {\n  case 1:\n  case 2:\n  case 3:\n    result = \"1, 2 o 3\";  // los 3 casos comparten este código\n    break;\n  case 4:\n    result = \"solo 4\";\n    break;\n  default:\n    result = \"otro valor\";\n}"}, {"tipo": "codigo", "codigo": "⚠️ No olvides el break\nSin break, el código sigue ejecutando los cases siguientes (fall-through). Úsalo intencionalmente solo cuando quieras que varios cases compartan código."}]}, {"numero": 8, "titulo": "Objetos (Objects)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Sintaxis básica"}, {"tipo": "codigo", "codigo": "const cat = {\n  \"name\": \"Whiskers\",\n  \"legs\": 4,\n  \"tails\": 1,\n  \"enemies\": [\"Water\", \"Dogs\"]\n};"}, {"tipo": "subtitulo", "texto": "Acceso a propiedades"}, {"tipo": "tabla", "filas": [["**Notación de punto (.)**", "**Notación de corchetes ([])**"], ["Cuando conoces el nombre exacto y no tiene espacios.", "Cuando la propiedad tiene espacios, o accedes con una variable."], ["obj.name   // 'Whiskers'", "obj[\"Space Name\"] const prop = 'legs'; obj[prop]  // 4"]]}, {"tipo": "subtitulo", "texto": "Modificar, agregar y eliminar propiedades"}, {"tipo": "codigo", "codigo": "ourDog.name = 'Happy';       // actualizar\nourDog[\"name\"] = \"Happy\";    // igual con corchetes\n\nourDog.bark = \"bow-wow\";     // agregar nueva propiedad\n\ndelete ourDog.bark;          // eliminar propiedad"}, {"tipo": "subtitulo", "texto": "Verificar si una propiedad existe"}, {"tipo": "codigo", "codigo": "obj.hasOwnProperty(\"name\");  // true / false"}, {"tipo": "subtitulo", "texto": "Búsqueda de perfil (lookUpProfile)"}, {"tipo": "texto", "texto": "Función que busca en un array de objetos por nombre y devuelve una propiedad:"}, {"tipo": "codigo", "codigo": "function lookUpProfile(name, prop) {\n  for (let i = 0; i < contacts.length; i++) {\n    if (contacts[i].firstName === name) {\n      if (contacts[i].hasOwnProperty(prop)) {\n        return contacts[i][prop];\n      } else {\n        return \"No such property\";\n      }\n    }\n  }\n  return \"No such contact\";\n}"}]}, {"numero": 9, "titulo": "Bucles (Loops)", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "while — ejecuta MIENTRAS la condición sea true"}, {"tipo": "codigo", "codigo": "const arr = [];\nlet i = 0;\nwhile (i < 5) {\n  arr.push(i);\n  i++;\n}\n// arr = [0, 1, 2, 3, 4]"}, {"tipo": "subtitulo", "texto": "for — para un número específico de repeticiones"}, {"tipo": "texto", "texto": "Sintaxis:  for (inicialización; condición; expresión final)"}, {"tipo": "codigo", "codigo": "for (let i = 0; i < 5; i++) {\n  arr.push(i);\n}\n\n// Números pares (saltos de 2):\nfor (let i = 0; i < 10; i += 2) { ... }\n\n// Cuenta regresiva:\nfor (let i = 10; i > 0; i -= 2) { ... }\n\n// Recorrer un array:\nfor (let i = 0; i < arr.length; i++) {\n  console.log(arr[i]);\n}"}, {"tipo": "subtitulo", "texto": "do...while — ejecuta AL MENOS una vez"}, {"tipo": "texto", "texto": "Diferencia clave: el código se ejecuta primero y la condición se evalúa después."}, {"tipo": "codigo", "codigo": "const arr = [];\nlet i = 5;\ndo {\n  arr.push(i);  // se ejecuta aunque i = 5 (no cumple while)\n  i++;\n} while (i < 5);\n// arr = [5]"}, {"tipo": "subtitulo", "texto": "for anidado — para arrays multidimensionales"}, {"tipo": "codigo", "codigo": "const arr = [[1, 2], [3, 4], [5, 6]];\n\nfor (let i = 0; i < arr.length; i++) {\n  for (let j = 0; j < arr[i].length; j++) {\n    console.log(arr[i][j]);\n  }\n}"}]}, {"numero": 10, "titulo": "Recursión", "bloque": "fundamentos", "contenido": [{"tipo": "texto", "texto": "Una función que se llama a sí misma. Siempre necesita un caso base (condición de parada) para no ejecutarse infinitamente."}, {"tipo": "subtitulo", "texto": "Estructura básica"}, {"tipo": "codigo", "codigo": "function recursiva(n) {\n  if (n <= 0) {    // CASO BASE — condición de parada\n    return 1;\n  } else {\n    return recursiva(n - 1) * n;  // LLAMADA RECURSIVA\n  }\n}"}, {"tipo": "subtitulo", "texto": "Ejemplo: multiply (equivalente a un for)"}, {"tipo": "codigo", "codigo": "function multiply(arr, n) {\n  if (n <= 0) return 1;\n  return multiply(arr, n - 1) * arr[n - 1];\n}"}, {"tipo": "subtitulo", "texto": "Ejemplo: countup (genera array [1..n])"}, {"tipo": "codigo", "codigo": "function countup(n) {\n  if (n < 1) return [];\n  const countArray = countup(n - 1);\n  countArray.push(n);\n  return countArray;\n}\ncountup(5); // [1, 2, 3, 4, 5]"}, {"tipo": "subtitulo", "texto": "Ejemplo: countdown (genera array [n..1])"}, {"tipo": "codigo", "codigo": "function countdown(n) {\n  if (n < 1) return [];\n  const arr = countdown(n - 1);\n  arr.unshift(n);\n  return arr;\n}\ncountdown(5); // [5, 4, 3, 2, 1]"}, {"tipo": "subtitulo", "texto": "Ejemplo: rangeOfNumbers (genera array [start..end])"}, {"tipo": "codigo", "codigo": "function rangeOfNumbers(startNum, endNum) {\n  if (startNum === endNum) return [startNum];\n  const arr = rangeOfNumbers(startNum, endNum - 1);\n  arr.push(endNum);\n  return arr;\n}\nrangeOfNumbers(1, 5); // [1, 2, 3, 4, 5]"}, {"tipo": "codigo", "codigo": "💡 Recuerda siempre\nSin caso base → bucle infinito y error. El caso base es lo primero que debes definir."}]}, {"numero": 11, "titulo": "Números Aleatorios", "bloque": "fundamentos", "contenido": [{"tipo": "subtitulo", "texto": "Fracción aleatoria (0 ≤ x ****<**** 1)"}, {"tipo": "codigo", "codigo": "Math.random();   // ej: 0.374829..."}, {"tipo": "subtitulo", "texto": "Entero aleatorio de 0 a N-1"}, {"tipo": "codigo", "codigo": "Math.floor(Math.random() * N);\n// Ej: 0 a 19\nMath.floor(Math.random() * 20);"}, {"tipo": "subtitulo", "texto": "Entero aleatorio dentro de un rango [min, max]"}, {"tipo": "codigo", "codigo": "Math.floor(Math.random() * (max - min + 1)) + min;\n\n// Ejemplo función:\nfunction randomRange(myMin, myMax) {\n  return Math.floor(Math.random() * (myMax - myMin + 1)) + myMin;\n}"}]}, {"numero": 12, "titulo": "parseInt()", "bloque": "fundamentos", "contenido": [{"tipo": "texto", "texto": "Convierte una cadena de texto en un número entero. Si no puede convertirla, devuelve NaN."}, {"tipo": "subtitulo", "texto": "Uso básico"}, {"tipo": "codigo", "codigo": "parseInt(\"007\");   // 7\nparseInt(\"3.14\"); // 3\nparseInt(\"abc\");  // NaN"}, {"tipo": "subtitulo", "texto": "Con base (radix) — especifica el sistema numérico"}, {"tipo": "codigo", "codigo": "parseInt(\"11\", 2);   // 3  (binario → decimal)\nparseInt(\"ff\", 16);  // 255 (hexadecimal → decimal)\n// La base puede ser entre 2 y 36"}, {"tipo": "subtitulo", "texto": "Arrays — métodos"}, {"tipo": "tabla", "filas": [["push(x)", "Agrega al FINAL"], ["pop()", "Elimina el ÚLTIMO y lo devuelve"], ["shift()", "Elimina el PRIMERO y lo devuelve"], ["unshift(x)", "Agrega al INICIO"]]}, {"tipo": "subtitulo", "texto": "Comparación — referencia rápida"}, {"tipo": "tabla", "filas": [["==  / !=", "Convierte tipos antes de comparar"], ["=== / !==", "NO convierte tipos (estricto)"], ["&&", "AND — ambas deben ser true"], ["││", "OR  — al menos una debe ser true"]]}, {"tipo": "subtitulo", "texto": "Bucles — cuándo usar cuál"}, {"tipo": "tabla", "filas": [["for", "Cuando sabes cuántas veces repetir"], ["while", "Cuando dependes de una condición que puede cambiar"], ["do...while", "Cuando necesitas ejecutar al menos 1 vez"]]}, {"tipo": "subtitulo", "texto": "Acceso a objetos"}, {"tipo": "tabla", "filas": [["obj.prop", "Notación de punto — nombre fijo sin espacios"], ["obj[\"prop\"]", "Corchetes — nombre con espacios o variable"], ["obj[variable]", "Corchetes — cuando el nombre viene de una variable"]]}, {"tipo": "texto", "texto": "ES6 es la versión 6 de ECMAScript (el estándar en que se basa JavaScript), lanzada en 2015. Introdujo herramientas modernas que hacen el código más limpio, corto y predecible. Todo lo que se ve en esta sección es lo que se usa hoy en cualquier proyecto real."}]}, {"numero": 13, "titulo": "var vs let — Alcance (Scope)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "El alcance define dónde vive una variable. var solo respeta funciones, let respeta cualquier bloque {}. Regla práctica: nunca uses var en código moderno."}, {"tipo": "codigo", "codigo": "// var — se escapa del bloque, solo la función la contiene\nfor (var i = 0; i < 3; i++) { }\nconsole.log(i); // 3 — i sobrevivió fuera del for\n\n// let — muere al cerrar el bloque {}\nfor (let i = 0; i < 3; i++) { }\nconsole.log(i); // Error: i is not defined"}]}, {"numero": 14, "titulo": "const — Constantes", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "const protege la referencia de la variable (no puedes reasignarla), pero el contenido de arrays y objetos sí puede modificarse. Úsala por defecto siempre."}, {"tipo": "codigo", "codigo": "const x = 5;\nx = 10; // Error — no puedes reasignar\n\nconst arr = [1, 2, 3];\narr = [4, 5]; // Error — no puedes reasignar\narr[0] = 99; // OK — sí puedes modificar el contenido\n\n// Cuándo usar cada uno:\nconst nombre = 'Juan';    // valor que no cambia\nconst usuarios = [];      // array que modificarás por dentro\nlet contador = 0;         // valor que reasignarás"}]}, {"numero": 15, "titulo": "Object.freeze — Congelar objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Object.freeze protege el CONTENIDO de un objeto o array. Ni const ni freeze solos son suficientes — juntos ofrecen protección total."}, {"tipo": "codigo", "codigo": "const obj = { PI: 3.14 };\n\n// Solo const — protege la referencia, no el contenido\nobj.PI = 99; // Permitido\n\n// Con freeze — protege también el contenido\nObject.freeze(obj);\nobj.PI = 99; // Error en modo estricto, ignorado en normal"}, {"tipo": "tabla", "filas": [["", "**Reasignar variable**", "**Modificar contenido**"], ["var / let", "✅ puede", "✅ puede"], ["const", "❌ no puede", "✅ puede"], ["const + freeze", "❌ no puede", "❌ no puede"]]}]}, {"numero": 16, "titulo": "Arrow Functions — Funciones Flecha", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Sintaxis corta para funciones anónimas. Muy usadas como argumentos de map, filter, forEach y similares."}, {"tipo": "codigo", "codigo": "// Función tradicional\nconst saludar = function(nombre) { return 'Hola ' + nombre; }\n\n// Arrow function con cuerpo\nconst saludar = (nombre) => { return 'Hola ' + nombre; }\n\n// Arrow function de una línea (sin return ni llaves)\nconst saludar = nombre => 'Hola ' + nombre;\n\n// Sin parámetros — paréntesis vacíos obligatorios\nconst saludar = () => 'Hola mundo';\n\n// Dos o más parámetros — paréntesis obligatorios\nconst sumar = (a, b) => a + b;"}]}, {"numero": 17, "titulo": "Parámetros por Defecto", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Permiten definir un valor de respaldo para un parámetro en caso de que no se pase ningún argumento al invocar la función."}, {"tipo": "codigo", "codigo": "// Sin default — si no pasas nada, es undefined\nconst saludar = (nombre) => 'Hola ' + nombre;\nsaludar(); // 'Hola undefined'\n\n// Con default — usa 'amigo' si no se pasa argumento\nconst saludar = (nombre = 'amigo') => 'Hola ' + nombre;\nsaludar();        // 'Hola amigo'\nsaludar('Juan');  // 'Hola Juan'"}]}, {"numero": 18, "titulo": "Rest Parameter (...)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Permite que una función acepte cualquier número de argumentos agrupándolos en un array. Siempre va al final de los parámetros."}, {"tipo": "codigo", "codigo": "// El nombre después de ... lo decides tú\nconst suma = (...args) => args.reduce((t, n) => t + n, 0);\nsuma(1, 2, 3);       // 6\nsuma(1, 2, 3, 4, 5); // 15\n\n// Combinado con parámetros normales\nconst primeroYResto = (primero, ...resto) => {\nconsole.log(primero); // primer argumento\nconsole.log(resto);   // array con los demás\n};"}]}, {"numero": 19, "titulo": "Spread Operator (...)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Expande un array en valores sueltos. Mismo símbolo que rest pero contexto diferente: rest junta, spread expande."}, {"tipo": "codigo", "codigo": "const arr = [6, 89, 3, 45];\n\n// Sin spread — no funciona\nMath.max(arr); // NaN\n\n// Con spread — expande el array\nMath.max(...arr); // 89\n\n// Copiar un array (copia independiente)\nconst arr2 = [...arr1]; // dos cajas diferentes con el mismo contenido\n\n// Regla: solo funciona dentro de algo\nconst x = ...arr;   // Error\nconst x = [...arr]; // OK"}, {"tipo": "tabla", "filas": [["", "**¿Dónde?**", "**¿Qué hace?**"], ["Rest ...args", "Parámetros de función", "Junta valores sueltos en array"], ["Spread ...arr", "Al invocar o en []", "Expande array en valores sueltos"]]}]}, {"numero": 20, "titulo": "Desestructuración de Objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Extrae propiedades de un objeto y las convierte en variables de forma directa. Evita escribir objeto.propiedad repetidamente."}, {"tipo": "codigo", "codigo": "const user = { name: 'Juan', age: 25, city: 'CDMX' };\n\n// Sin desestructuración — repetitivo\nconst name = user.name;\nconst age  = user.age;\n\n// Con desestructuración — una sola línea\nconst { name, age } = user;\n\n// Con renombre — dos puntos para cambiar el nombre de la variable\nconst { name: userName, age: userAge } = user;\n\n// Objetos anidados\nconst { john: { age, nationality } } = obj;"}]}, {"numero": 21, "titulo": "Desestructuración de Arrays", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Extrae elementos de un array y los asigna a variables. A diferencia de los objetos, el orden importa."}, {"tipo": "codigo", "codigo": "const [a, b] = [1, 2, 3, 4, 5];\n// a = 1, b = 2\n\n// Saltar elementos con comas\nconst [a, b,,, c] = [1, 2, 3, 4, 5];\n// a=1, b=2, c=5 (se saltaron posiciones 3 y 4)\n\n// Intercambiar variables sin variable temporal\nlet a = 8, b = 6;\n[a, b] = [b, a]; // a=6, b=8\n\n// Con rest — guardar lo que sobra\nconst [x, y, ...resto] = [1, 2, 3, 4, 5];\n// x=1, y=2, resto=[3,4,5]"}]}, {"numero": 22, "titulo": "Desestructuración en Parámetros de Función", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Se puede desestructurar el objeto directamente en el parámetro de la función, evitando un paso extra dentro del cuerpo."}, {"tipo": "codigo", "codigo": "// Forma larga — desestructuras adentro\nconst mostrar = (user) => {\nconst { name, age } = user;\nreturn name + ' tiene ' + age + ' años';\n}\n\n// Forma corta ES6 — desestructuras en el parámetro directamente\nconst mostrar = ({ name, age }) => name + ' tiene ' + age + ' años';\n\n// Se invoca igual en ambos casos\nmostrar({ name: 'Juan', age: 25 });"}]}, {"numero": 23, "titulo": "Template Literals — Plantillas de Texto", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Usan comillas invertidas (`) en lugar de comillas normales. Permiten insertar variables con ${} y escribir strings multilínea sin \\n."}, {"tipo": "codigo", "codigo": "const nombre = 'Juan';\nconst edad = 25;\n\n// Concatenación antigua — feo y propenso a errores\nconst msg = 'Hola ' + nombre + ', tienes ' + edad + ' años';\n\n// Template literal — limpio y legible\nconst msg = `Hola ${nombre}, tienes ${edad} años`;\n\n// Expresiones dentro de ${}\nconst msg = `El doble es ${edad * 2}`;\n\n// Multilínea sin \\n\nconst texto = `Línea 1\nLínea 2\nLínea 3`;"}]}, {"numero": 24, "titulo": "Notación Abreviada de Objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Cuando el nombre del parámetro y el nombre de la propiedad son iguales, ES6 permite escribirlo solo una vez."}, {"tipo": "codigo", "codigo": "const x = 10, y = 20;\n\n// Forma larga — nombre repetido\nconst punto = { x: x, y: y };\n\n// Forma corta ES6 — solo una vez\nconst punto = { x, y };\n\n// En funciones que retornan objetos\nconst getPunto = (x, y) => ({ x, y });\ngetPunto(3, 5); // { x: 3, y: 5 }"}]}, {"numero": 25, "titulo": "Métodos Concisos en Objetos", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "ES6 permite declarar funciones dentro de objetos sin usar la palabra clave function ni los dos puntos."}, {"tipo": "codigo", "codigo": "// ES5 — con function y dos puntos\nconst persona = {\nnombre: 'Ana',\nsaludar: function() { return 'Hola ' + this.nombre; }\n};\n\n// ES6 — sin function ni dos puntos\nconst persona = {\nnombre: 'Ana',\nsaludar() { return `Hola ${this.nombre}`; }\n};"}]}, {"numero": 26, "titulo": "Clases (class)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Una clase es un molde o plantilla para crear múltiples objetos con la misma estructura. Ideal cuando necesitas crear muchos objetos del mismo tipo."}, {"tipo": "codigo", "codigo": "class Usuario {\nconstructor(nombre, edad) {  // se ejecuta automáticamente con new\nthis.nombre = nombre;      // this = el objeto que se está creando\nthis.edad = edad;\n}\nsaludar() {                  // método disponible para todos los objetos\nreturn `Hola, soy ${this.nombre}`;\n}\n}\n\n// Crear objetos desde la clase\nconst juan = new Usuario('Juan', 25);\nconst ana  = new Usuario('Ana', 30);\n\njuan.nombre;    // 'Juan'\njuan.saludar(); // 'Hola, soy Juan'\n\n// Acceso desde afuera: nombreObjeto.propiedad\n// Acceso desde adentro: this.propiedad"}]}, {"numero": 27, "titulo": "Getters y Setters", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "get controla cómo se leen las propiedades de un objeto. set controla cómo se modifican, pudiendo validar o transformar los datos antes de guardarlos. Se usan como propiedades, no como funciones."}, {"tipo": "codigo", "codigo": "class Temperatura {\nconstructor(fahrenheit) {\nthis._temp = fahrenheit; // _ indica propiedad 'privada' (convención)\n}\nget temperatura() {\nreturn 5/9 * (this._temp - 32); // convierte a Celsius al leer\n}\nset temperatura(celsius) {\nthis._temp = celsius * 9/5 + 32; // convierte a Fahrenheit al guardar\n}\n}\n\nconst t = new Temperatura(76);\nt.temperatura;     // lee — devuelve 24.44°C (get)\nt.temperatura = 26; // escribe — guarda 78.8°F (set)\n\n// Con validación en set\nset edad(valor) {\nif (typeof valor !== 'number' ││ valor < 0) return;\nthis._edad = valor;\n}"}]}, {"numero": 28, "titulo": "Módulos — export e import", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "ES6 permite compartir código entre archivos JavaScript. Se necesita type='module' en el HTML para activar esta funcionalidad."}, {"tipo": "codigo", "codigo": "<!-- En el HTML — activa los módulos -->\n<script type=\"module\" src=\"index.js\"></script>\n\n// En math.js — exportar\nexport const add = (x, y) => x + y;\nexport const subtract = (x, y) => x - y;\nexport { add, subtract }; // forma alternativa agrupada\n\n// export default — para la exportación principal del archivo\nexport default function multiply(x, y) { return x * y; }\n\n// En app.js — importar\nimport { add, subtract } from './math.js';     // selectivo\nimport * as math from './math.js';             // todo en un objeto\nimport multiply from './math.js';              // default (sin llaves)\n\nmath.add(2, 3);   // usando import *\nadd(2, 3);        // usando import selectivo"}, {"tipo": "tabla", "filas": [["**Tipo**", "**Exportar**", "**Importar**"], ["Normal", "export { fn }", "import { fn } from './file.js'"], ["Default", "export default fn", "import fn from './file.js'"], ["Todo", "export { a, b, c }", "import * as obj from './file.js'"]]}]}, {"numero": 29, "titulo": "Promesas (Promise)", "bloque": "es6", "contenido": [{"tipo": "texto", "texto": "Una promesa representa una operación que tarda tiempo (llamadas a APIs, bases de datos, etc.) y que puede cumplirse o rechazarse. Permiten que el código siga ejecutándose sin bloquearse esperando el resultado."}, {"tipo": "codigo", "codigo": "// Crear una promesa\nconst miPromesa = new Promise((resolve, reject) => {\n// operación que tarda tiempo...\nif (exito) {\nresolve('Datos obtenidos'); // se cumplió\n} else {\nreject('Error al obtener datos'); // no se cumplió\n}\n});\n\n// Manejar el resultado\nmiPromesa\n.then(resultado => {\nconsole.log(resultado); // se ejecuta si resolve()\n})\n.catch(error => {\nconsole.log(error); // se ejecuta si reject()\n});"}, {"tipo": "tabla", "filas": [["**Estado**", "**Qué significa**"], ["pending", "Esperando — aún no hay resultado"], ["fulfilled", "resolve() fue llamado — éxito ✅"], ["rejected", "reject() fue llamado — falló ❌"]]}, {"tipo": "texto", "texto": "Las expresiones regulares son patrones que se usan para buscar, validar o manipular texto. En JavaScript se escriben entre diagonales /patron/ y se combinan con metodos como .test() y .match()."}]}, {"numero": 30, "titulo": "Metodos .test() y .match()", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": ".test() verifica si existe una coincidencia y devuelve true o false. .match() extrae las coincidencias y devuelve un array o null. La sintaxis es inversa entre ambos."}, {"tipo": "codigo", "codigo": "// .test() — la regex llama al metodo, la cadena va adentro\n/Code/.test('freeCodeCamp'); // true\n/xyz/.test('freeCodeCamp');  // false\n\n// .match() — la cadena llama al metodo, la regex va adentro\n'freeCodeCamp'.match(/Code/); // ['Code']\n'freeCodeCamp'.match(/xyz/);  // null\n\n// REGLA: cadena.match(regex) — NO regex.match(cadena)"}]}, {"numero": 31, "titulo": "Banderas (Flags)", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Las banderas modifican el comportamiento de la busqueda. Se agregan despues del ultimo / de la regex. Se pueden combinar varias banderas."}, {"tipo": "tabla", "filas": [["**Bandera**", "**Nombre**", "**Que hace**"], ["i", "Case insensitive", "Ignora mayusculas y minusculas"], ["g", "Global", "Encuentra TODAS las coincidencias, no solo la primera"], ["gi", "Ambas", "Todas las coincidencias sin importar mayusculas"]]}, {"tipo": "codigo", "codigo": "/hello/i.test('Hello World');   // true — ignora mayusculas\n'Repeat Repeat'.match(/repeat/gi); // ['Repeat', 'Repeat']"}]}, {"numero": 32, "titulo": "Caracteres Especiales y Comodin", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "El punto . es el comodin — coincide con cualquier caracter excepto salto de linea. El operador | funciona como OR para buscar varias alternativas."}, {"tipo": "codigo", "codigo": "/hu./  — coincide con hug, hum, hut, hub, etc.\n/yes│no│maybe/ — coincide con 'yes', 'no' o 'maybe'\n\n// El OR │ para patrones completos\n/cat│dog/.test('I have a cat'); // true\n\n// El comodin . para cualquier caracter\n'hug'.match(/hu./); // ['hug']\n'hum'.match(/hu./); // ['hum']"}]}, {"numero": 33, "titulo": "Clases de Caracteres [ ]", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los corchetes [] definen un grupo de caracteres posibles en esa posicion. Con ^ adentro se niega la clase. Con - se definen rangos."}, {"tipo": "codigo", "codigo": "// Clase normal — busca a, i o u en esa posicion\n/b[aiu]g/ — coincide con bag, big, bug (no bog)\n\n// Rango de letras\n/[a-z]/ — cualquier letra minuscula\n/[A-Za-z0-9]/ — letras y numeros\n\n// Rango de numeros\n/[0-5]/ — numeros del 0 al 5\n\n// Clase negada — busca lo que NO esta en la lista\n/[^aeiou]/ — cualquier cosa que NO sea vocal\n/[^0-9]/ — cualquier cosa que NO sea numero"}]}, {"numero": 34, "titulo": "Atajos de Clases (Shorthand)", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "JavaScript tiene atajos predefinidos para clases comunes. Minuscula = busca ESO, Mayuscula = busca lo OPUESTO."}, {"tipo": "tabla", "filas": [["**Atajo**", "**Equivalente**", "**Busca**"], ["\\w", "[A-Za-z0-9_]", "Letras, numeros y guion bajo"], ["\\W", "[^A-Za-z0-9_]", "Todo lo que NO es alfanumerico"], ["\\d", "[0-9]", "Solo digitos"], ["\\D", "[^0-9]", "Todo lo que NO es digito"], ["\\s", "[ \\r\\t\\f\\n\\v]", "Espacios en blanco y saltos"], ["\\S", "[^ \\r\\t\\f\\n\\v]", "Todo lo que NO es espacio"]]}, {"tipo": "codigo", "codigo": "'Hello123'.match(/\\w/g);  // ['H','e','l','l','o','1','2','3']\n'Hello 123!'.match(/\\W/g); // [' ', '!']\n'abc123'.match(/\\d/g);    // ['1','2','3']\n'abc 123'.match(/\\s/g);   // [' ']"}]}, {"numero": 35, "titulo": "Cuantificadores", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los cuantificadores indican cuantas veces debe aparecer el caracter o grupo anterior."}, {"tipo": "tabla", "filas": [["**Cuantificador**", "**Significado**", "**Ejemplo**"], ["+", "Uno o mas (consecutivos)", "/s+/ en 'Mississippi' → ['ss','ss']"], ["*", "Cero o mas (consecutivos)", "/go*/ en 'gooal' → ['gooo']"], ["?", "Cero o uno (opcional)", "/colou?r/ → 'color' y 'colour'"], ["{n}", "Exactamente n veces", "/a{3}/ → 'aaa'"], ["{n,}", "Minimo n veces", "/a{2,}/ → 'aa', 'aaa', 'aaaa'..."], ["{n,m}", "Entre n y m veces", "/a{2,4}/ → 'aa', 'aaa', 'aaaa'"]]}, {"tipo": "codigo", "codigo": "/a+/.test('abc');   // true — al menos una 'a'\n/a*/.test('bc');    // true — cero 'a' tambien vale\n/Oh{3,6} no/        — 'Ohhh no' hasta 'Ohhhhhh no'\n/\\d{4}/            — exactamente 4 digitos"}]}, {"numero": 36, "titulo": "Anclas ^ y $", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Las anclas no buscan caracteres, definen la posicion en la cadena. ^ ancla al inicio, $ ancla al final. Juntos validan la cadena completa."}, {"tipo": "codigo", "codigo": "// ^ fuera de corchetes = inicio de cadena\n/^Ricky/.test('Ricky is first'); // true\n/^Ricky/.test('You found Ricky'); // false\n\n// $ = final de cadena\n/story$/.test('This is a story'); // true\n/story$/.test('story will end');  // false\n\n// Juntos = validan la cadena completa\n/^\\d+$/.test('123');     // true — solo numeros\n/^\\d+$/.test('123abc'); // false — tiene letras\n\n// IMPORTANTE: ^ dentro de [] niega la clase\n/[^aeiou]/ — NO es ancla, es negacion de vocales"}]}, {"numero": 37, "titulo": "Coincidencia Greedy vs Lazy", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Por defecto las regex son greedy (glotonas) — capturan lo mas posible. Con ? despues del cuantificador se vuelven lazy (perezosas) — capturan lo minimo posible."}, {"tipo": "codigo", "codigo": "let html = '<h1>Titulo</h1>';\n\n// Greedy — llega hasta el ULTIMO >\nhtml.match(/<.*>/);  // ['<h1>Titulo</h1>']\n\n// Lazy — para en el PRIMER >\nhtml.match(/<.*?>/); // ['<h1>']\n\n// Regla:\n.*   = greedy, llega hasta el ultimo caracter que cumpla\n.*?  = lazy, para en el primero que cumpla"}]}, {"numero": 38, "titulo": "Grupos de Captura ( ) y Reutilizacion", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los parentesis () crean grupos de captura numerados. Se reusan con \\1, \\2 en la misma regex, o con $1, $2 en .replace()."}, {"tipo": "codigo", "codigo": "// Reutilizar en la misma regex con \\1\n/^(\\d+) \\1 \\1$/.test('42 42 42'); // true\n/^(\\d+) \\1 \\1$/.test('42 42 43'); // false\n\n// Reordenar con $1, $2 en .replace()\n'Code Camp'.replace(/(\\w+)\\s(\\w+)/, '$2 $1');\n// Resultado: 'Camp Code'\n\n// Eliminar espacios del principio y final\nlet wsRegex = /^\\s+│\\s+$/g;\n'  Hola  '.replace(wsRegex, ''); // 'Hola'"}]}, {"numero": 39, "titulo": "Lookaheads — Aserciones de Anticipacion", "bloque": "regex", "contenido": [{"tipo": "texto", "texto": "Los lookaheads verifican que algo exista o no exista adelante en la cadena, sin consumir caracteres. Muy utiles para validar contrasenas con multiples condiciones."}, {"tipo": "codigo", "codigo": "// Lookahead positivo (?=) — verifica que SI este presente\n/q(?=u)/.test('quit');  // true — 'q' seguida de 'u'\n/q(?=u)/.test('qt');    // false — no hay 'u' despues\n\n// Lookahead negativo (?!) — verifica que NO este presente\n/q(?!u)/.test('qt');    // true — 'q' sin 'u' despues\n\n// Validar contrasena: mas de 5 chars Y dos numeros seguidos\n/(?=\\w{6,})(?=\\D*\\d{2})/\n// Condicion 1: 6 o mas caracteres alfanumericos\n// Condicion 2: en algun punto hay dos digitos consecutivos\n\n// Cada (?=...) es independiente — ambos deben cumplirse"}]}, {"numero": 40, "titulo": "Tabla Resumen de Expresiones Regulares", "bloque": "regex", "contenido": [{"tipo": "tabla", "filas": [["**Patron**", "**Que busca**"], [".", "Cualquier caracter excepto salto de linea"], ["\\w / \\W", "Alfanumerico / No alfanumerico"], ["\\d / \\D", "Digito / No digito"], ["\\s / \\S", "Espacio / No espacio"], ["[abc]", "a, b o c en esa posicion"], ["[^abc]", "Cualquier cosa MENOS a, b o c"], ["[a-z]", "Rango de caracteres"], ["^ / $", "Inicio / Final de cadena"], ["+ / * / ?", "1+, 0+, 0 o 1 repeticiones"], ["{n,m}", "Entre n y m repeticiones"], ["a│b", "a o b (alternativa)"], ["(abc)", "Grupo de captura"], ["\\1 / $1", "Reutilizar grupo 1"], ["(?=...) / (?!...)", "Lookahead positivo / negativo"], [".*  / .*?", "Greedy / Lazy"]]}, {"tipo": "texto", "texto": "La depuracion es el proceso de encontrar y corregir errores en el codigo. JavaScript tiene varios tipos de errores: sintaxis, referencia, tipo y logica. Las herramientas principales son console.log() y typeof."}]}, {"numero": 41, "titulo": "Metodos de Consola", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "La consola del navegador muestra todos los metodos. freeCodeCamp solo muestra console.log(). Usar estos metodos en puntos estrategicos del codigo ayuda a identificar errores."}, {"tipo": "tabla", "filas": [["**Metodo**", "**Color**", "**Para que sirve**"], ["console.log()", "Blanco", "Imprimir cualquier valor — el mas usado"], ["console.warn()", "Amarillo ⚠️", "Advertencias — algo puede fallar"], ["console.error()", "Rojo ❌", "Errores graves — algo fallo"], ["console.info()", "Azul", "Informacion general"], ["console.table()", "Tabla visual", "Ver arrays u objetos de forma clara"], ["console.time()", "Cronometro", "Medir cuanto tarda una operacion"], ["console.count()", "Contador", "Contar cuantas veces se ejecuta una linea"], ["console.clear()", "Limpia", "Borrar toda la consola"]]}, {"tipo": "codigo", "codigo": "console.log('valor:', miVariable);      // debug general\nconsole.warn('Cuidado con esto');       // advertencia\nconsole.error('Algo salio mal');        // error\nconsole.table([1, 2, 3]);              // muestra como tabla\n\nconsole.time('operacion');             // inicia cronometro\n// ... codigo a medir ...\nconsole.timeEnd('operacion');          // detiene y muestra tiempo\n\nconsole.clear();                       // limpia la consola"}]}, {"numero": 42, "titulo": "typeof — Verificar Tipos", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "typeof devuelve el tipo de dato de una variable como string. Muy util cuando el resultado de una operacion es inesperado — puede ser que los tipos no sean los que crees."}, {"tipo": "codigo", "codigo": "typeof 'hola'       // 'string'\ntypeof 42           // 'number'\ntypeof true         // 'boolean'\ntypeof undefined    // 'undefined'\ntypeof null         // 'object' — quirk historico de JS\ntypeof []           // 'object' — los arrays son objetos\ntypeof {}           // 'object'\ntypeof function(){} // 'function'\n\n// Uso practico para detectar errores\nconsole.log(typeof miVariable); // ver que tipo llego realmente\n\n// Ejemplo de error silencioso\nlet num = '5';  // string, no number!\nnum + 3;        // '53' en lugar de 8"}]}, {"numero": 43, "titulo": "Errores Comunes de Sintaxis", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "Estos errores impiden que el codigo se ejecute. El navegador o Node los reporta con un mensaje de error especifico."}, {"tipo": "codigo", "codigo": "// 1. Errores de ortografia en variables — case sensitive\nlet netWorkingCapital = 100;\nconsole.log(networkingcapital); // ReferenceError — nombre diferente\n\n// 2. Pares sin cerrar\nlet arr = [1, 2, 3;  // falta ]\nfunction suma(a, b {  // falta )\n\n// 3. Comillas mezcladas\nlet str = 'It's a problem'; // cierra en el apostrofe\nlet str = \"It's fine\";     // OK — comillas diferentes\nlet str = 'It\\'s fine';    // OK — apostrofe escapado\n\n// 4. = en lugar de == o ===\nif (x = 5) { }   // asigna 5 a x, siempre true\nif (x === 5) { } // compara — correcto"}]}, {"numero": 44, "titulo": "Errores Comunes de Logica", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "Estos errores no detienen el codigo pero producen resultados incorrectos. Son los mas dificiles de encontrar porque no generan mensajes de error."}, {"tipo": "codigo", "codigo": "// 1. Olvidar () al invocar una funcion\nlet resultado = miFuncion;  // guarda la funcion, no la ejecuta\nlet resultado = miFuncion(); // ejecuta y guarda el resultado\n\n// 2. Argumentos en orden incorrecto\nfunction potencia(base, exp) { return base ** exp; }\npotencia(3, 2); // 9 — correcto\npotencia(2, 3); // 8 — incorrecto si quieres 3^2\n\n// 3. Indexacion incorrecta (Off-by-one)\nlet arr = [1, 2, 3]; // indices: 0, 1, 2\narr[arr.length];     // undefined — fuera de rango\narr[arr.length - 1]; // 3 — ultimo elemento correcto\n\nfor (let i = 0; i <= arr.length; i++) { } // itera de mas\nfor (let i = 0; i < arr.length; i++) { }  // correcto\n\n// 4. Reinicializar variables dentro del bucle incorrecto\nfor (let i = 0; i < m; i++) {\nlet row = [];        // se reinicia en cada vuelta externa OK\nfor (let j = 0; j < n; j++) {\nrow.push(0);       // llena la fila\n}\nnewArray.push(row);  // agrega la fila completa\n}\n\n// 5. Bucle infinito — condicion que nunca se cumple\nfor (let i = 1; i != 4; i += 2) { } // 1,3,5... nunca llega a 4\nfor (let i = 1; i <= 4; i += 2) { } // correcto"}]}, {"numero": 45, "titulo": "Estrategia de Depuracion", "bloque": "debug", "contenido": [{"tipo": "texto", "texto": "Cuando el codigo no funciona, sigue este proceso para encontrar el error rapidamente."}, {"tipo": "codigo", "codigo": "// Paso 1 — Lee el mensaje de error si hay uno\n// ReferenceError: x is not defined → variable mal escrita o fuera de scope\n// TypeError: x is not a function → olvidaste () o el tipo es incorrecto\n// SyntaxError → par sin cerrar, comillas mal, etc.\n\n// Paso 2 — Agrega console.log en puntos clave\nfunction miFuncion(datos) {\nconsole.log('datos recibidos:', datos);      // que llego\nconsole.log('tipo:', typeof datos);           // que tipo es\n// ... resto del codigo ...\nconsole.log('resultado:', resultado);         // que salio\n}\n\n// Paso 3 — Verifica tipos con typeof\n// Si esperas un numero y obtienes '53' en lugar de 8,\n// probablemente uno de los valores es string\n\n// Paso 4 — Revisa condiciones de bucles\n// i < length vs i <= length\n// condicion que nunca se cumple = bucle infinito\n\n// Paso 5 — Verifica el orden de los argumentos\n// Lee la definicion de la funcion y compara con la llamada"}, {"tipo": "texto", "texto": "Los arrays y objetos son las estructuras de datos mas usadas en JavaScript. Los arrays almacenan colecciones ordenadas, los objetos almacenan pares clave-valor. Ambos son mutables y pueden contener cualquier tipo de dato."}]}, {"numero": 46, "titulo": "Metodos de Arrays — Agregar y Eliminar", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "Los arrays tienen metodos para agregar y eliminar elementos en cualquier posicion. Todos modifican el array original excepto slice()."}, {"tipo": "tabla", "filas": [["**Metodo**", "**Donde actua**", "**Retorna**"], ["push(elem)", "Agrega al FINAL", "Nueva longitud del array"], ["pop()", "Elimina del FINAL", "El elemento eliminado"], ["unshift(elem)", "Agrega al INICIO", "Nueva longitud del array"], ["shift()", "Elimina del INICIO", "El elemento eliminado"], ["splice(i, n, ...elems)", "Elimina/agrega en cualquier posicion", "Array con elementos eliminados"], ["slice(inicio, fin)", "Extrae sin modificar el original", "Nuevo array con los elementos"]]}, {"tipo": "codigo", "codigo": "let arr = ['a', 'b', 'c'];\n\narr.push('d');         // ['a', 'b', 'c', 'd']\narr.pop();             // ['a', 'b', 'c'] — devuelve 'd'\narr.unshift('z');      // ['z', 'a', 'b', 'c']\narr.shift();           // ['a', 'b', 'c'] — devuelve 'z'\n\n// splice(indice, cuantoEliminar, ...elementosAgregar)\narr.splice(1, 1);          // elimina 'b' → ['a', 'c']\narr.splice(1, 0, 'x', 'y'); // agrega sin eliminar → ['a', 'x', 'y', 'c']\narr.splice(1, 2, 'b');      // reemplaza 2 por 1 → ['a', 'b', 'c']\n\n// slice(inicio, fin) — fin NO incluido, no modifica el original\nlet nuevo = arr.slice(1, 3); // ['b', 'c']\nconsole.log(arr);            // ['a', 'b', 'c'] — intacto"}]}, {"numero": 47, "titulo": "Spread Operator con Arrays", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "El operador spread ... permite copiar arrays, combinarlos e insertar elementos en cualquier posicion. Ya visto en ES6 — se aplica igual con arrays."}, {"tipo": "codigo", "codigo": "// Copiar un array — copia independiente\nlet original = [1, 2, 3];\nlet copia = [...original];  // [1, 2, 3] — no es la misma referencia\n\n// Combinar arrays\nlet a = ['a', 'b'];\nlet b = ['c', 'd'];\nlet combinado = [...a, ...b];        // ['a', 'b', 'c', 'd']\nlet insertado = ['z', ...a, ...b];   // ['z', 'a', 'b', 'c', 'd']\n\n// Copiar N veces dentro de un array de arrays\nlet resultado = [];\nfor (let i = 0; i < 3; i++) {\nresultado.push([...original]);  // agrega copia independiente cada vez\n}"}]}, {"numero": 48, "titulo": "indexOf() y Busqueda en Arrays", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "indexOf() busca un elemento en el array y devuelve su posicion. Si no existe devuelve -1. Util para verificar si algo existe antes de operar."}, {"tipo": "codigo", "codigo": "let frutas = ['manzana', 'pera', 'uva', 'pera'];\n\nfrutas.indexOf('pera');       // 1 — primera aparicion\nfrutas.indexOf('mango');      // -1 — no existe\n\n// Verificar si existe\nif (frutas.indexOf('uva') !== -1) {\nconsole.log('Existe');\n}\n\n// Caso de uso real — evitar duplicados\nfunction agregarSiNoExiste(arr, elem) {\nif (arr.indexOf(elem) === -1) {\narr.push(elem);\n}\nreturn arr;\n}"}]}, {"numero": 49, "titulo": "Arrays Multidimensionales", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "Un array puede contener otros arrays de profundidad arbitraria. Se accede con notacion de corchetes encadenada. Cada nivel requiere un par de corchetes adicional."}, {"tipo": "codigo", "codigo": "// Array bidimensional — 2 niveles\nlet matriz = [[1, 2], [3, 4], [5, 6]];\nmatriz[0][1];  // 2 — fila 0, columna 1\nmatriz[2][0];  // 5 — fila 2, columna 0\n\n// Array multidimensional — varios niveles\nlet profundo = [[['deep'], ['deep2']], [['deeper']]];\nprofundo[0][0][0];  // 'deep'\nprofundo[1][0][0];  // 'deeper'\n\n// Recorrer con for anidado\nfor (let i = 0; i < matriz.length; i++) {\nfor (let j = 0; j < matriz[i].length; j++) {\nconsole.log(matriz[i][j]);\n}\n}"}]}, {"numero": 50, "titulo": "Metodos de Objetos", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "Los objetos tienen sus propios metodos para agregar, eliminar, verificar y recorrer propiedades. Las claves no tienen orden garantizado."}, {"tipo": "codigo", "codigo": "const obj = { nombre: 'Juan', edad: 25 };\n\n// Agregar o modificar propiedades\nobj.ciudad = 'CDMX';          // notacion de punto\nobj['email'] = 'j@gmail.com'; // notacion de corchetes\n\n// Notacion de corchetes con variable — acceso dinamico\nlet propiedad = 'nombre';\nobj[propiedad];  // 'Juan' — busca la propiedad con ese valor\nobj.propiedad;   // undefined — busca literalmente 'propiedad'\n\n// Eliminar propiedad\ndelete obj.edad;  // obj ya no tiene 'edad'\n\n// Verificar si existe una propiedad\nobj.hasOwnProperty('nombre');  // true\n'nombre' in obj;               // true — incluye propiedades heredadas\n\n// Obtener todas las claves como array\nObject.keys(obj);  // ['nombre', 'ciudad', 'email']\n\n// Recorrer todas las claves con for...in\nfor (const clave in obj) {\nconsole.log(clave, obj[clave]);\n}\n\n// Modificar array dentro de objeto\nobj.amigos = ['Ana', 'Luis'];\nobj.amigos.push('Maria');  // accede al array y lo modifica"}]}, {"numero": 51, "titulo": "for...in vs for normal", "bloque": "data", "contenido": [{"tipo": "texto", "texto": "El for...in recorre las claves de un objeto. El for normal recorre indices de un array. Cada uno es la herramienta correcta para su estructura."}, {"tipo": "codigo", "codigo": "// for normal — para arrays (con indice)\nconst arr = ['a', 'b', 'c'];\nfor (let i = 0; i < arr.length; i++) {\nconsole.log(i, arr[i]);  // 0 'a', 1 'b', 2 'c'\n}\n\n// for...in — para objetos (con claves)\nconst obj = { x: 1, y: 2, z: 3 };\nfor (const clave in obj) {\nconsole.log(clave, obj[clave]);  // x 1, y 2, z 3\n}\n\n// Caso practico — contar usuarios online\nfunction contarOnline(usuarios) {\nlet count = 0;\nfor (const user in usuarios) {\nif (usuarios[user].online === true) count++;\n}\nreturn count;\n}"}, {"tipo": "texto", "texto": "*Este bloque aplica todo lo aprendido hasta ahora para resolver 16 problemas reales. No hay teoria de golpe — cada ejercicio introduce herramientas cuando las necesitas. El enfoque es: dividir el problema, identificar las herramientas correctas y combinarlas.*"}]}, {"numero": 52, "titulo": "split() y join() — Dividir y Unir Strings", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "split() convierte un string en array usando un separador. join() hace lo inverso: une los elementos de un array en un string. Son el duo estandar cuando necesitas procesar palabras individuales de una frase."}, {"tipo": "codigo", "codigo": "// split(separador) — string a array\n'hola mundo'.split(' ');   // ['hola', 'mundo']\n'a,b,c'.split(',');        // ['a', 'b', 'c']\n'hola'.split('');          // ['h','o','l','a'] — caracter por caracter\n\n// join(separador) — array a string\n['hola', 'mundo'].join(' ');  // 'hola mundo'\n['a','b','c'].join('-');      // 'a-b-c'\n['a','b','c'].join('');       // 'abc' — sin separador\n\n// IMPORTANTE: join() NO modifica el array original\n// Debes guardar su resultado en una variable\nconst result = arr.join(' ');  // correcto\narr.join(' ');                 // el resultado se pierde\n\n// Patron clasico: split → procesar → join\nfunction titleCase(str) {\nconst palabras = str.split(' ');\nconst resultado = [];\nfor (let i = 0; i < palabras.length; i++) {\nresultado.push(palabras[i][0].toUpperCase() + palabras[i].slice(1).toLowerCase());\n}\nreturn resultado.join(' ');\n}"}]}, {"numero": 53, "titulo": "charAt(), toUpperCase() y toLowerCase()", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Metodos para transformar el casing de strings. charAt(n) accede al caracter en la posicion n — equivalente a str[n] pero mas explicito. Muy usados juntos para capitalizar palabras."}, {"tipo": "codigo", "codigo": "// charAt(n) — equivalente a str[n]\n'hello'.charAt(0);   // 'h'\n'hello'[0];          // 'h' — ambas formas funcionan\n\n// toUpperCase() / toLowerCase()\n'hello'.toUpperCase();  // 'HELLO'\n'WORLD'.toLowerCase();  // 'world'\n\n// Capitalizar una palabra: primera letra mayuscula + resto minuscula\nfunction capitalizar(palabra) {\nreturn palabra.charAt(0).toUpperCase() + palabra.slice(1).toLowerCase();\n}\ncapitalizar('hELLO');  // 'Hello'\n\n// Para ignorar mayusculas al comparar\nstr1.toLowerCase() === str2.toLowerCase();"}]}, {"numero": 54, "titulo": "includes() — Verificar si algo existe", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "includes() devuelve true si el elemento o subcadena existe, false si no. Funciona en strings (busca texto) y en arrays (busca elementos). A diferencia de indexOf(), devuelve booleano directamente."}, {"tipo": "codigo", "codigo": "// En strings — busca subcadenas\n'hello world'.includes('world');   // true\n'hello world'.includes('xyz');     // false\n\n// En arrays — busca elementos\n[1, 2, 3].includes(2);   // true\n[1, 2, 3].includes(9);   // false\n\n// Diferencia clave con indexOf()\narr.indexOf('x') !== -1  // forma antigua\narr.includes('x')        // forma moderna, mas legible\n\n// Busqueda letra por letra en un string (Mutations)\nfunction mutation(arr) {\nconst str1 = arr[0].toLowerCase();\nconst str2 = arr[1].toLowerCase();\nfor (let i = 0; i < str2.length; i++) {\nif (!str1.includes(str2[i])) return false;\n}\nreturn true;\n}\n// includes() con letra individual verifica existencia,\n// NO que aparezca como subcadena continua"}]}, {"numero": 55, "titulo": "Math.max() y Math.min() con Spread", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Math.max() y Math.min() reciben numeros separados por comas, no un array. El spread operator (...) expande el array en argumentos individuales, haciendo que funcionen juntos."}, {"tipo": "codigo", "codigo": "// Math.max / Math.min con valores sueltos\nMath.max(1, 5, 3);   // 5\nMath.min(1, 5, 3);   // 1\n\n// Con un array directamente — NO funciona\nMath.max([1, 5, 3]); // NaN\n\n// Con spread — expande el array como argumentos\nconst nums = [1, 5, 3];\nMath.max(...nums);   // 5\nMath.min(...nums);   // 1\n\n// Caso de uso: mayor de cada sub-array (Return Largest Numbers)\nfunction largestOfFour(arr) {\nconst result = [];\nfor (let i = 0; i < arr.length; i++) {\nresult.push(Math.max(...arr[i]));\n}\nreturn result;\n}\nlargestOfFour([[4,5,1,3],[13,27,18,26]]);  // [5, 27]"}]}, {"numero": 56, "titulo": "sort() con Comparador Numerico", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "sort() sin argumentos ordena como texto (1, 10, 2...). Para ordenar numeros correctamente se necesita una funcion comparadora. El comparador (a, b) => a - b ordena de menor a mayor."}, {"tipo": "codigo", "codigo": "// sort() sin comparador — ordena como texto (INCORRECTO para numeros)\n[10, 1, 21, 2].sort();          // [1, 10, 2, 21] — INCORRECTO\n\n// sort() con comparador numerico\n[10, 1, 21, 2].sort((a, b) => a - b);  // [1, 2, 10, 21] — ascendente\n[10, 1, 21, 2].sort((a, b) => b - a);  // [21, 10, 2, 1] — descendente\n\n// Logica del comparador:\n// a - b < 0  → a va primero\n// a - b > 0  → b va primero\n// a - b = 0  → igual, no cambia\n\n// Caso de uso: ordenar antes de buscar indice de insercion\nfunction getIndexToIns(arr, num) {\narr.sort((a, b) => a - b);\nfor (let i = 0; i < arr.length; i++) {\nif (arr[i] >= num) return i;\n}\nreturn arr.length;  // num es mayor que todos\n}\ngetIndexToIns([40, 60], 50);  // 1"}]}, {"numero": 57, "titulo": "typeof — Operador, no Metodo", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "typeof ya estaba en tus apuntes como tip, pero en este bloque se usa directamente para resolver ejercicios. El error comun es usarlo como propiedad (valor.typeof) cuando en realidad es un operador que va ANTES del valor."}, {"tipo": "codigo", "codigo": "// typeof va ANTES del valor — es operador, no metodo\ntypeof 'hola'       // 'string'\ntypeof 42           // 'number'\ntypeof true         // 'boolean'\ntypeof undefined    // 'undefined'\ntypeof null         // 'object' — comportamiento historico de JS\ntypeof []           // 'object'\ntypeof function(){} // 'function'\n\n// Error comun — typeof como propiedad\nbool.typeof         // ERROR — no existe\ntypeof bool         // CORRECTO\n\n// Siempre devuelve un STRING — comparar con comillas\ntypeof bool == 'boolean'   // correcto\ntypeof bool == boolean     // ERROR — boolean sin comillas no existe\n\n// Uso practico (Boo Who)\nfunction booWho(bool) {\nreturn typeof bool === 'boolean';\n}"}]}, {"numero": 58, "titulo": "Boolean() y Valores Falsy", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "JavaScript tiene 6 valores falsy — todo lo demas es truthy. Boolean() convierte cualquier valor a su equivalente booleano. Util para filtrar valores no deseados de arrays."}, {"tipo": "tabla", "filas": [["**Valor Falsy**", "**Por que es falso**"], ["false", "El booleano falso"], ["0", "El numero cero"], ["\"\"  (string vacio)", "String sin contenido"], ["null", "Ausencia intencional de valor"], ["undefined", "Variable declarada sin valor"], ["NaN", "Not a Number — resultado de operacion invalida"]]}, {"tipo": "codigo", "codigo": "// Boolean() convierte a true o false\nBoolean(0);         // false\nBoolean('');        // false\nBoolean(null);      // false\nBoolean(undefined); // false\nBoolean(NaN);       // false\nBoolean(false);     // false\n\nBoolean(1);         // true\nBoolean('hola');    // true\nBoolean([]);        // true — array vacio es truthy\nBoolean({});        // true — objeto vacio es truthy\n\n// Uso en if — estas dos formas son equivalentes\nif (Boolean(valor) === true) { ... }\nif (Boolean(valor)) { ... }  // mas corto\nif (valor) { ... }           // mas corto aun — JS evalua truthy/falsy\n\n// Filtrar falsy de un array (Falsy Bouncer)\nfunction bouncer(arr) {\nconst result = [];\nfor (let i = 0; i < arr.length; i++) {\nif (Boolean(arr[i])) result.push(arr[i]);\n}\nreturn result;\n}\nbouncer([7, 'ate', '', false, 9]);  // [7, 'ate', 9]"}]}, {"numero": 59, "titulo": "Callbacks — Funciones como Argumentos", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Una funcion puede recibir otra funcion como argumento. Esa funcion se llama callback. No defines que evalua — solo la ejecutas pasandole el elemento actual. Es la base de metodos como filter(), map() y forEach() que vienen mas adelante."}, {"tipo": "codigo", "codigo": "// Una funcion que recibe otra funcion como argumento\nfunction findElement(arr, func) {\nfor (let i = 0; i < arr.length; i++) {\nif (func(arr[i])) return arr[i];  // ejecutas func con cada elemento\n}\nreturn undefined;\n}\n\n// Al llamarla, pasas la logica como argumento\nfindElement([1, 3, 5, 8], function(num) { return num % 2 === 0; });\n// Devuelve 8 — primer numero par\n\n// Con arrow function — mas corto, mismo resultado\nfindElement([1, 3, 5, 8], num => num % 2 === 0);\n\n// El callback puede ser cualquier logica\nfindElement([1, 3, 5, 8], num => num > 4);  // devuelve 5\n\n// Tu funcion NO sabe ni le importa que evalua el callback\n// Solo lo ejecuta: func(elemento) y revisa si devuelve true o false"}]}, {"numero": 60, "titulo": "Patrones Algoritmicos Esenciales", "bloque": "algoritmos", "contenido": [{"tipo": "texto", "texto": "Estos patrones aparecieron en varios ejercicios del bloque. Reconocerlos te permite atacar problemas nuevos mas rapido porque ya sabes que herramientas combinar."}, {"tipo": "codigo", "codigo": "// PATRON 1: Variable acumuladora (Reverse String, Repeat String)\nlet resultado = '';\nfor (let i = str.length - 1; i >= 0; i--) {\nresultado += str[i];\n}\n\n// PATRON 2: Variable de maximo / minimo (Longest Word)\nlet maximo = 0;\nfor (let i = 0; i < arr.length; i++) {\nif (arr[i].length > maximo) maximo = arr[i].length;\n}\n\n// PATRON 3: split → procesar → join (Title Case)\nconst palabras = str.split(' ');\n// ... procesar cada palabra ...\nreturn palabras.join(' ');\n\n// PATRON 4: Copiar array antes de mutarlo (Slice and Splice)\nconst copia = [...arr2];       // spread\nconst copia2 = arr2.slice();   // slice sin argumentos\ncopia.splice(n, 0, ...arr1);   // modificas la copia, no el original\n\n// PATRON 5: Bucle con saltos (Chunky Monkey)\nfor (let i = 0; i < arr.length; i += size) {\nresult.push(arr.slice(i, i + size));\n}\n\n// PATRON 6: Ordenar + buscar posicion (Where Do I Belong)\narr.sort((a, b) => a - b);\nfor (let i = 0; i < arr.length; i++) {\nif (arr[i] >= num) return i;\n}\nreturn arr.length;"}, {"tipo": "texto", "texto": "Programacion Orientada a Objetos"}, {"tipo": "texto", "texto": "*Este bloque explica como JavaScript organiza y reutiliza codigo mediante objetos, herencia y encapsulamiento. Es la base de como estan construidos los frameworks, librerias y sistemas reales que usamos todos los dias.*"}]}, {"numero": 61, "titulo": "La Palabra Clave this", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "this siempre se refiere al objeto que esta ejecutando el metodo. Sin this, un metodo tendria que usar el nombre de la variable directamente — si renombras el objeto, todo el codigo que lo referencia se rompe. Con this, el metodo siempre apunta al objeto correcto sin importar como se llame."}, {"tipo": "codigo", "codigo": "let duck = {\nname: 'Donald',\n// Sin this — fragil, depende del nombre 'duck'\nsayName: function() { return 'Me llamo ' + duck.name; }\n};\n\nlet duck = {\nname: 'Donald',\n// Con this — reutilizable, no depende del nombre\nsayName: function() { return 'Me llamo ' + this.name; }\n};\n\n// this dentro de un metodo = el objeto dueno del metodo\nduck.sayName();  // 'Me llamo Donald'"}]}, {"numero": 62, "titulo": "Constructores — La Forma Clasica (Pre-ES6)", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Antes de ES6 y las clases, los objetos se creaban con funciones constructoras. El nombre va en PascalCase para distinguirlos de funciones normales. Internamente es lo mismo que class — ES6 solo agrego una sintaxis mas limpia encima."}, {"tipo": "codigo", "codigo": "// Forma clasica — function constructor\nfunction Persona(nombre, edad) {\nthis.nombre = nombre;  // propiedad propia\nthis.edad   = edad;    // propiedad propia\n}\n\n// Forma moderna — class (ES6) — mismo resultado\nclass Persona {\nconstructor(nombre, edad) {\nthis.nombre = nombre;\nthis.edad   = edad;\n}\n}\n\n// Convenciones del constructor:\n// 1. Nombre en PascalCase (Persona, no persona)\n// 2. Usa this para definir propiedades\n// 3. No retorna valor — crea el objeto automaticamente con new"}]}, {"numero": 63, "titulo": "new e Instancias", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "El operador new crea un nuevo objeto a partir del constructor. Sin new, this no apunta al nuevo objeto y el resultado es incorrecto. Cada objeto creado con new es una instancia independiente con sus propias propiedades."}, {"tipo": "codigo", "codigo": "function Bird(nombre, color) {\nthis.nombre = nombre;\nthis.color  = color;\nthis.patas  = 2;\n}\n\n// new crea una instancia nueva\nlet pato   = new Bird('Donald', 'blanco');\nlet canario = new Bird('Tweety',  'amarillo');\n\n// Cada instancia tiene sus propias copias\npato.nombre;    // 'Donald'\ncanario.nombre; // 'Tweety'\n\n// Modificar una no afecta a la otra\npato.nombre = 'Daffy';\ncanario.nombre; // 'Tweety' — sin cambios"}]}, {"numero": 64, "titulo": "instanceof y Propiedad constructor", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "instanceof verifica si un objeto fue creado con un constructor especifico. La propiedad constructor apunta a la funcion que creo el objeto. instanceof es mas confiable porque la propiedad constructor puede ser sobreescrita accidentalmente."}, {"tipo": "codigo", "codigo": "function Bird() {}\nlet pato = new Bird();\n\n// instanceof — pregunta desde el objeto\npato instanceof Bird;    // true\npato instanceof Object;  // true — todo hereda de Object\n\n// propiedad constructor — referencia al creador\npato.constructor === Bird;    // true\npato.constructor === Object;  // false\n\n// Uso practico — verificar tipo antes de procesar\nfunction procesarAve(candidato) {\nif (candidato instanceof Bird) {\nreturn 'Es un ave';\n}\nreturn 'No es un ave';\n}"}]}, {"numero": 65, "titulo": "Propiedades Propias vs Prototype", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Las propiedades propias viven dentro de cada instancia — cada objeto carga su copia. Las propiedades de prototype viven en un lugar compartido — todos los objetos acceden a la misma. En produccion, los metodos van en prototype para no duplicar codigo en memoria."}, {"tipo": "codigo", "codigo": "function Bird(nombre) {\nthis.nombre = nombre;  // propiedad propia — cada pajaro tiene la suya\n}\n\n// Metodo en prototype — una sola copia compartida por todas las instancias\nBird.prototype.volar = function() {\nconsole.log(this.nombre + ' esta volando');\n};\n\nlet pato = new Bird('Donald');\n\n// Propiedad propia — aparece en el objeto\nconsole.log(pato);           // { nombre: 'Donald' }\npato.hasOwnProperty('nombre'); // true\n\n// Propiedad de prototype — no aparece en el objeto pero es accesible\npato.volar();                  // 'Donald esta volando' — funciona\npato.hasOwnProperty('volar');  // false — esta en prototype, no en el objeto\n\n// Sin prototype: 1000 pajaros = 1000 copias de volar()\n// Con prototype: 1000 pajaros = 1 sola copia compartida"}]}, {"numero": 66, "titulo": "Iterar y Clasificar Propiedades", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "for...in recorre TODAS las propiedades accesibles — propias y de prototype. hasOwnProperty permite clasificarlas: si retorna true es propia, si retorna false es del prototype."}, {"tipo": "codigo", "codigo": "function Bird(nombre) { this.nombre = nombre; }\nBird.prototype.patas = 2;\n\nlet pato = new Bird('Donald');\n\nlet propiasProp    = [];\nlet prototypeProp  = [];\n\nfor (let propiedad in pato) {\nif (pato.hasOwnProperty(propiedad)) {\npropiasProp.push(propiedad);   // ['nombre']\n} else {\nprototypeProp.push(propiedad); // ['patas']\n}\n}\n\n// Resultado:\n// propiasProp   = ['nombre']  — viven en el objeto\n// prototypeProp = ['patas']   — viven en Bird.prototype"}]}, {"numero": 67, "titulo": "Asignar Objeto Completo al Prototype", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "En vez de agregar propiedades al prototype una por una, puedes asignarle un objeto completo. IMPORTANTE: esto borra la propiedad constructor — siempre hay que redeclararla manualmente."}, {"tipo": "codigo", "codigo": "// Forma lenta — una por una\nBird.prototype.patas   = 2;\nBird.prototype.volar   = function() { console.log('volando'); };\nBird.prototype.comer   = function() { console.log('comiendo'); };\n\n// Forma rapida — objeto completo\nBird.prototype = {\nconstructor: Bird,  // OBLIGATORIO — se borra al reasignar prototype\npatas: 2,\nvolar: function() { console.log('volando'); },\ncomer: function() { console.log('comiendo'); }\n};\n\n// Si olvidas constructor: Bird:\nlet pato = new Bird('Donald');\npato.constructor === Bird;    // false — PROBLEMA\npato.constructor === Object;  // true  — incorrecto\n\n// Con constructor: Bird declarado:\npato.constructor === Bird;    // true  — correcto"}]}, {"numero": 68, "titulo": "Cadena de Prototipos", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Todo objeto en JavaScript tiene un prototype. El prototype a su vez tiene su propio prototype. Esto forma una cadena. Cuando buscas una propiedad, JavaScript sube por la cadena hasta encontrarla o llegar a null. Por eso hasOwnProperty, toString y otros metodos funcionan en cualquier objeto sin haberlos definido."}, {"tipo": "codigo", "codigo": "// La cadena completa para un pajaro:\n// pato\n//   → Bird.prototype       (volar, comer — metodos del pajaro)\n//     → Object.prototype   (hasOwnProperty, toString, valueOf...)\n//       → null             — fin de la cadena\n\n// Verificar la cadena con isPrototypeOf\nBird.prototype.isPrototypeOf(pato);    // true — Bird es padre de pato\nObject.prototype.isPrototypeOf(Bird.prototype); // true — Object es abuelo\n\n// Por eso esto funciona sin haberlo definido:\npato.hasOwnProperty('nombre');  // viene de Object.prototype\npato.toString();                // viene de Object.prototype\n\n// Cuando buscas pato.volar():\n// 1. Busca en pato        — no esta\n// 2. Busca en Bird.prototype — ENCONTRADO, ejecuta\n// Cuando buscas pato.hasOwnProperty():\n// 1. Busca en pato             — no esta\n// 2. Busca en Bird.prototype   — no esta\n// 3. Busca en Object.prototype — ENCONTRADO, ejecuta"}]}, {"numero": 69, "titulo": "Herencia — Object.create() y Supertipos", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Cuando varios constructores comparten metodos, se crea un padre (supertipo) con lo comun. Object.create(Parent.prototype) conecta el hijo al padre. Siempre hay que reparar el constructor despues de la conexion."}, {"tipo": "codigo", "codigo": "// PADRE — supertipo con comportamiento comun\nfunction Animal() {}\nAnimal.prototype = {\nconstructor: Animal,\ncomer: function() { console.log('nom nom nom'); },\ndormir: function() { console.log('zzz...'); }\n};\n\n// HIJO — hereda de Animal\nfunction Perro(nombre) {\nthis.nombre = nombre;\n}\n\n// 1. Conectar hijo al padre\nPerro.prototype = Object.create(Animal.prototype);\n\n// 2. Reparar constructor (se borra al hacer Object.create)\nPerro.prototype.constructor = Perro;\n\n// 3. Agregar metodos propios del hijo\nPerro.prototype.ladrar = function() { console.log('guau!'); };\n\n// Resultado — el perro tiene todo:\nlet rex = new Perro('Rex');\nrex.comer();   // heredado de Animal\nrex.ladrar();  // propio de Perro\n\nrex instanceof Perro;   // true\nrex instanceof Animal;  // true — tambien es un Animal"}]}, {"numero": 70, "titulo": "Sobreescribir Metodos Heredados", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Un hijo puede redefinir un metodo heredado del padre. JavaScript usa el primero que encuentra en la cadena — si el hijo lo tiene, nunca llega al padre. Util cuando el comportamiento general no aplica para un caso especifico."}, {"tipo": "codigo", "codigo": "function Animal() {}\nAnimal.prototype.describir = function() {\nreturn 'Soy un animal';\n};\n\nfunction Pinguino() {}\nPinguino.prototype = Object.create(Animal.prototype);\nPinguino.prototype.constructor = Pinguino;\n\n// Sobreescribir — mismo nombre, diferente comportamiento\nPinguino.prototype.describir = function() {\nreturn 'Soy un pinguino, no puedo volar';\n};\n\nlet skipper = new Pinguino();\nskipper.describir(); // 'Soy un pinguino, no puedo volar'\n// JavaScript encuentra describir() en Pinguino.prototype\n// y se detiene — nunca llega a Animal.prototype\n\n// Busqueda en la cadena:\n// 1. skipper propio       — no tiene describir\n// 2. Pinguino.prototype   — ENCONTRADO, ejecuta este\n// 3. Animal.prototype     — nunca llega aqui"}]}, {"numero": 71, "titulo": "Mixins — Compartir entre Objetos No Relacionados", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "La herencia conecta objetos con relacion familiar. Los mixins comparten habilidades entre objetos sin relacion. Un Ave y un Avion no son familia pero ambos pueden volar. En produccion: exportarPDF, registrarAuditoria, enviarNotificacion — habilidades que muchos tipos necesitan."}, {"tipo": "codigo", "codigo": "// Mixin — funcion que agrega metodos a cualquier objeto\nconst volarMixin = function(obj) {\nobj.volar = function() { console.log('volando!'); };\n};\n\nlet ave   = { nombre: 'Aguila', patas: 2 };\nlet avion = { modelo: '737',    motores: 2 };\n\n// Ambos reciben la habilidad sin relacion familiar\nvolarMixin(ave);\nvolarMixin(avion);\n\nave.volar();   // 'volando!'\navion.volar(); // 'volando!'\n\n// Caso real — exportarPDF lo necesitan Usuario, Reporte y Factura\n// No tienen relacion entre si, pero comparten esa habilidad\nconst exportarMixin = function(obj) {\nobj.exportarPDF = function() {\nreturn 'Exportando ' + JSON.stringify(this);\n};\n};"}]}, {"numero": 72, "titulo": "Closures — Propiedades Privadas", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Una variable declarada con let dentro del constructor es privada — nada fuera puede accederla directamente. Solo los metodos definidos en el mismo contexto pueden leerla. En produccion: contrasenas, saldos, tokens — datos que no deben exponerse al exterior."}, {"tipo": "codigo", "codigo": "function CuentaBancaria(saldoInicial) {\n// Variable privada — nadie fuera puede modificarla directamente\nlet _saldo = saldoInicial;\n\n// Metodos privilegiados — unico acceso al saldo\nthis.getSaldo  = function() { return _saldo; };\nthis.depositar = function(monto) { _saldo += monto; };\nthis.retirar   = function(monto) {\nif (monto > _saldo) return 'Saldo insuficiente';\n_saldo -= monto;\n};\n}\n\nlet cuenta = new CuentaBancaria(1000);\n\ncuenta.getSaldo();     // 1000 — acceso por la ventanilla\ncuenta.depositar(500); // saldo interno: 1500\ncuenta._saldo;         // undefined — no existe para afuera\ncuenta._saldo = 99999; // no tiene efecto — _saldo sigue siendo 1500\n\n// El closure hace que getSaldo y depositar 'recuerden'\n// el contexto donde nacieron y por eso pueden acceder a _saldo"}]}, {"numero": 73, "titulo": "IIFE y Modulos", "bloque": "oop", "contenido": [{"tipo": "texto", "texto": "Una IIFE (Immediately Invoked Function Expression) se declara y ejecuta al instante. Combinada con un objeto de retorno forma un modulo — agrupa funcionalidad relacionada sin contaminar el scope global. Asi estan construidas librerias como jQuery, Lodash y los sistemas internos de frameworks como React."}, {"tipo": "codigo", "codigo": "// IIFE basica — se ejecuta sola\n(function() {\nconsole.log('Ejecutado al instante');\n})();\n\n// Modulo con IIFE — agrupa mixins o funcionalidad relacionada\nlet ModuloPagos = (function() {\n// Variables privadas del modulo\nlet _tasaImpuesto = 0.16;\n\n// Solo esto es visible desde afuera\nreturn {\ncalcularTotal: function(precio) {\nreturn precio + (precio * _tasaImpuesto);\n},\npagarConTarjeta: function(obj) {\nobj.pagar = function(monto) {\nconsole.log('Tarjeta: $' + monto);\n};\n},\npagarEfectivo: function(obj) {\nobj.pagar = function(monto) {\nconsole.log('Efectivo: $' + monto);\n};\n}\n};\n})();\n\n// Uso desde afuera\nModuloPagos.calcularTotal(100);  // 116\nModuloPagos._tasaImpuesto;       // undefined — es privada\n\nlet orden = {};\nModuloPagos.pagarConTarjeta(orden);\norden.pagar(500);  // 'Tarjeta: $500'"}, {"tipo": "texto", "texto": "— Fin de los apuntes —"}]}], "actualizado": "junio 2026", "total": 73};
